import React from 'react';
import { Car, LogOut, Search, Plus, History } from 'lucide-react';

const Header = ({ user, onLogout, currentView, setCurrentView, onAuthClick }) => {
  return (
    <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <button 
            onClick={() => setCurrentView('home')}
            className="flex items-center gap-3"
          >
            <div className="bg-blue-600 p-2 rounded-lg">
              <Car className="text-white" size={24} />
            </div>
            <span className="text-xl font-bold text-gray-900">RideShare Pro</span>
          </button>

          <nav className="hidden md:flex items-center gap-6">
            <button
              onClick={() => setCurrentView('home')}
              className={`flex items-center gap-2 px-3 py-2 rounded-lg ${currentView === 'home' ? 'bg-blue-50 text-blue-600' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Search size={18} />
              <span>Find Rides</span>
            </button>
            <button
              onClick={() => {
                if (user) {
                  setCurrentView('offer');
                } else {
                  onAuthClick('signup');
                }
              }}
              className={`flex items-center gap-2 px-3 py-2 rounded-lg ${currentView === 'offer' ? 'bg-blue-50 text-blue-600' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Plus size={18} />
              <span>Offer Ride</span>
            </button>
            <button
              onClick={() => {
                if (user) {
                  setCurrentView('my-rides');
                } else {
                  onAuthClick('login');
                }
              }}
              className={`flex items-center gap-2 px-3 py-2 rounded-lg ${currentView === 'my-rides' ? 'bg-blue-50 text-blue-600' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <History size={18} />
              <span>My Rides</span>
            </button>
          </nav>

          <div className="flex items-center gap-4">
            {user ? (
              <>
                <div className="text-right hidden sm:block">
                  <div className="text-sm font-medium text-gray-900">{user.name}</div>
                  <div className="text-xs text-gray-500">⭐ {user.rating} · {user.ridesCompleted} rides</div>
                </div>
                <button
                  onClick={onLogout}
                  className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                  title="Logout"
                >
                  <LogOut size={20} />
                </button>
              </>
            ) : (
              <>
                <button
                  onClick={() => onAuthClick('login')}
                  className="text-gray-700 hover:text-gray-900 font-medium"
                >
                  Login
                </button>
                <button
                  onClick={() => onAuthClick('signup')}
                  className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 font-medium"
                >
                  Sign Up
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
